# frozen_string_literal: true
#
# Manual port of examples/c/hello-world.c using the autogenerated Ruby
# bindings (see doc/src/codegen/v2/lang_ruby/). The data flow is identical:
# a single-counter model is upcast into a RefAny, the layout callback
# rebuilds the DOM each frame, and the button click increments the counter
# and asks for a redraw.

require 'azul'

# Pull in the Azul classes we want at the top level. We deliberately do
# NOT `include Azul` because that would shadow Ruby's built-in `String`
# with `Azul::String`. Listing names explicitly keeps `String` intact.
App                       = Azul::App
AppConfig                 = Azul::AppConfig
Button                    = Azul::Button
Css                       = Azul::Css
CssProperty               = Azul::CssProperty
CssPropertyWithConditions = Azul::CssPropertyWithConditions
Dom                       = Azul::Dom
RefAny                    = Azul::RefAny
StyleFontSize             = Azul::StyleFontSize
Update                    = Azul::Update
WindowCreateOptions       = Azul::WindowCreateOptions
WindowDecorations         = Azul::WindowDecorations
WindowBackgroundMaterial  = Azul::WindowBackgroundMaterial
ButtonType                = Azul::ButtonType
AzString                  = Azul::String # AzString helper alias for clarity

# ── Data model ──────────────────────────────────────────────────────────

# Plain Ruby holder. Native code only ever sees the upcast RefAny — the
# Ruby object itself is just a convenient place to keep state during
# layout/click callbacks.
DataModel = Struct.new(:counter)

# ── Callback: button click ──────────────────────────────────────────────

on_click = lambda do |data, _info|
  d = Azul::MyDataModel.downcast_mut(data)
  if d.nil?
    Update::DoNothing
  else
    d.counter += 1
    Update::RefreshDom
  end
end

# ── Callback: layout (rebuilds DOM each frame) ──────────────────────────

layout = lambda do |data, _info|
  d = Azul::MyDataModel.downcast_ref(data)
  next Dom.create_body if d.nil?

  # Counter label (wrapped in a div so the font-size sticks)
  label_text = AzString.copy_from_string(d.counter.to_s)
  label = Dom.create_text(label_text)
  label_wrapper = Dom.create_div
  label_wrapper.add_css_property(
    CssPropertyWithConditions.simple(
      CssProperty.font_size(StyleFontSize.px(32.0))
    )
  )
  label_wrapper.add_child(label)

  # Increment button
  button = Button.create(AzString.copy_from_string('Increase counter'))
  button.set_button_type(ButtonType::Primary)
  button.set_on_click(RefAny.clone(data), on_click)
  button_dom = button.dom

  # Body
  body = Dom.create_body
  body.add_child(label_wrapper)
  body.add_child(button_dom)
  body.style(Css.empty)
end

# ── Main ────────────────────────────────────────────────────────────────

model = DataModel.new(5)
data = Azul::MyDataModel.upcast(model)

window = WindowCreateOptions.create(layout)
window.window_state.title = AzString.copy_from_string('Hello World')
window.window_state.size.dimensions.width = 400.0
window.window_state.size.dimensions.height = 300.0

# NoTitleAutoInject: OS draws close/min/max buttons,
# framework auto-injects a Titlebar with drag support.
window.window_state.flags.decorations         = WindowDecorations::NoTitleAutoInject
window.window_state.flags.background_material = WindowBackgroundMaterial::Sidebar

app = App.create(data, AppConfig.create)
app.run(window)
